Object.keys(_bulkExpansion).forEach(catId => {
  const cat = VOCABULARY_DATA.categories.find(c => c.id === catId);
  if (cat) {
    const toAdd = 100 - cat.words.length;
    if (toAdd > 0) {
      cat.words.push(..._bulkExpansion[catId].slice(0, toAdd));
    }
  }
});

if (typeof window !== 'undefined') { window.VOCABULARY_DATA = VOCABULARY_DATA; }
